export default {
  name: 'QuoteCard',
  props: {
    quote: {
      type: Object,
      required: true
    }
  },
  emits: ['click'],
  methods: {
    formatDate(dateString) {
      const date = new Date(dateString);
      return date.toLocaleDateString('fr-FR', {
        year: 'numeric',
        month: 'long',
        day: 'numeric',
        hour: '2-digit',
        minute: '2-digit'
      });
    },
    formatPrice(price) {
      return parseFloat(price).toFixed(2);
    },
    getStatusLabel(status) {
      const labels = {
        pending_validation: 'En attente',
        validated: 'Validé',
        expired: 'Expiré',
        converted: 'Converti'
      };
      return labels[status] || status;
    }
  }
};
